{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "urn:cpcs-mx:authoring-schema:1.0",
  "title": "CPCS-MX YAML/JSON Authoring Document",
  "type": "object",
  "required": [
    "cpcs_mx"
  ],
  "properties": {
    "cpcs_mx": {
      "type": "object",
      "required": [
        "schema",
        "document_id"
      ],
      "properties": {
        "schema": {
          "const": "urn:cpcs-mx:schema:1.0"
        },
        "document_id": {
          "type": "string",
          "minLength": 1
        },
        "extends": {
          "type": "array",
          "items": {
            "type": "string"
          }
        },
        "imports": {
          "type": "object",
          "additionalProperties": {
            "type": "object",
            "required": [
              "type",
              "path"
            ],
            "properties": {
              "type": {
                "enum": [
                  "json",
                  "yaml",
                  "asset",
                  "jsonl",
                  "xml"
                ]
              },
              "path": {
                "type": "string"
              },
              "sha256": {
                "type": "string"
              }
            },
            "additionalProperties": true
          }
        },
        "scope": {
          "type": "object",
          "additionalProperties": true
        },
        "project": {
          "type": "object",
          "additionalProperties": true
        },
        "shot": {
          "type": "object",
          "additionalProperties": true
        },
        "character": {
          "type": "object",
          "additionalProperties": true
        },
        "characters": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": true
          }
        },
        "action_graph": {
          "type": "array",
          "items": {
            "type": "object",
            "required": [
              "id"
            ],
            "additionalProperties": true
          }
        },
        "performance": {
          "type": "object",
          "additionalProperties": true
        },
        "capture_style": {
          "type": "object",
          "additionalProperties": true
        },
        "style_switch": {
          "type": "object",
          "additionalProperties": true
        },
        "style_transform": {
          "type": "object",
          "additionalProperties": true
        },
        "virtual_physics": {
          "type": "object",
          "additionalProperties": true
        },
        "secondary_motion": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": true
          }
        },
        "hard_constraints": {
          "type": "array",
          "items": {
            "type": [
              "string",
              "object"
            ]
          }
        },
        "soft_constraints": {
          "type": "array",
          "items": {
            "type": [
              "string",
              "object"
            ]
          }
        },
        "overrides": {
          "type": "object",
          "additionalProperties": true
        },
        "locks": {
          "type": "array",
          "items": {
            "type": "object",
            "required": [
              "path",
              "value"
            ],
            "additionalProperties": true
          }
        },
        "verification": {
          "type": "object",
          "additionalProperties": true
        },
        "metadata": {
          "type": "object",
          "additionalProperties": true
        }
      },
      "additionalProperties": true
    }
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "urn:cpcs-mx:observation-record:1.0",
  "title": "CPCS-MX Observation or Verification JSONL Record",
  "type": "object",
  "required": [
    "record_id",
    "source_id",
    "layer",
    "claim",
    "evidence_class",
    "extractor"
  ],
  "properties": {
    "record_id": {
      "type": "string",
      "minLength": 1
    },
    "source_id": {
      "type": "string",
      "minLength": 1
    },
    "frame_index": {
      "type": "integer",
      "minimum": 0
    },
    "pts_s": {
      "type": "number"
    },
    "time_range": {
      "type": "object",
      "required": [
        "start_s",
        "end_s"
      ],
      "properties": {
        "start_s": {
          "type": "number"
        },
        "end_s": {
          "type": "number"
        }
      },
      "additionalProperties": false
    },
    "clock": {
      "type": "string"
    },
    "layer": {
      "type": "string"
    },
    "subject_ref": {
      "type": "string"
    },
    "claim": {
      "type": "object",
      "required": [
        "type"
      ],
      "properties": {
        "type": {
          "type": "string"
        }
      },
      "additionalProperties": true
    },
    "evidence_class": {
      "enum": [
        "measured",
        "detected",
        "inferred",
        "interpreted",
        "authored",
        "defaulted",
        "derived"
      ]
    },
    "confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1
    },
    "alternatives": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": true
      }
    },
    "extractor": {
      "type": "object",
      "required": [
        "name",
        "version"
      ],
      "properties": {
        "name": {
          "type": "string"
        },
        "version": {
          "type": "string"
        },
        "pass": {
          "type": "string"
        }
      },
      "additionalProperties": true
    },
    "review_status": {
      "enum": [
        "unreviewed",
        "reviewed",
        "locked",
        "rejected"
      ]
    },
    "supersedes": {
      "type": "array",
      "items": {
        "type": "string"
      }
    },
    "metadata": {
      "type": "object",
      "additionalProperties": true
    }
  },
  "anyOf": [
    {
      "required": [
        "frame_index"
      ]
    },
    {
      "required": [
        "pts_s"
      ]
    },
    {
      "required": [
        "time_range"
      ]
    }
  ],
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "urn:cpcs-mx:rag-record-schema:1.0",
  "title": "CPCS-MX RAG JSONL Record",
  "type": "object",
  "required": [
    "record_id",
    "record_type",
    "document_id",
    "title",
    "content",
    "sha256"
  ],
  "properties": {
    "record_id": {
      "type": "string",
      "minLength": 1
    },
    "record_type": {
      "enum": [
        "document",
        "research_chunk",
        "schema_definition",
        "field_guide",
        "worked_example",
        "source",
        "prompt_template",
        "validation_rule",
        "migration_note",
        "package_document"
      ]
    },
    "document_id": {
      "type": "string",
      "minLength": 1
    },
    "parent_id": {
      "type": [
        "string",
        "null"
      ]
    },
    "title": {
      "type": "string",
      "minLength": 1
    },
    "heading_path": {
      "type": "array",
      "items": {
        "type": "string"
      }
    },
    "concepts": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "uniqueItems": true
    },
    "evidence_labels": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "uniqueItems": true
    },
    "source_ids": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^S[0-9]{3}$"
      },
      "uniqueItems": true
    },
    "schema_fields": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "uniqueItems": true
    },
    "safety_scope": {
      "type": "string"
    },
    "content": {
      "type": "string",
      "minLength": 1
    },
    "context_before": {
      "type": "string"
    },
    "context_after": {
      "type": "string"
    },
    "source_uri": {
      "type": "string"
    },
    "metadata": {
      "type": "object",
      "additionalProperties": true
    },
    "sha256": {
      "type": "string",
      "pattern": "^[A-Fa-f0-9]{64}$"
    }
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "urn:cpcs-mx:schema:1.0",
  "title": "CPCS-MX Canonical Motion Score",
  "description": "Canonical, resolved representation for hierarchical character motion, performance, style, presentation, constraints, provenance, and verification.",
  "type": "object",
  "required": [
    "schema_id",
    "document_id",
    "timebase"
  ],
  "properties": {
    "$schema": {
      "type": "string"
    },
    "schema_id": {
      "const": "urn:cpcs-mx:schema:1.0"
    },
    "document_id": {
      "$ref": "#/$defs/stableId"
    },
    "title": {
      "type": "string",
      "minLength": 1
    },
    "description": {
      "type": "string"
    },
    "safety_scope": {
      "type": "string",
      "minLength": 1
    },
    "rights_scope": {
      "type": "object",
      "additionalProperties": {
        "type": [
          "string",
          "number",
          "boolean",
          "null"
        ]
      }
    },
    "timebase": {
      "$ref": "#/$defs/timebase"
    },
    "coordinate_systems": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/coordinateSystem"
      }
    },
    "assets": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/asset"
      }
    },
    "entities": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/entity"
      }
    },
    "characters": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/character"
      }
    },
    "rigs": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/rig"
      }
    },
    "style_profiles": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/styleProfile"
      }
    },
    "shots": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/shot"
      }
    },
    "phases": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/phase"
      }
    },
    "tracks": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/track"
      }
    },
    "events": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/event"
      }
    },
    "contacts": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/contact"
      }
    },
    "laban_controls": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/labanControl"
      }
    },
    "facial_events": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/facialEvent"
      }
    },
    "breath_tracks": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/breathTrack"
      }
    },
    "mannerism_profiles": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/mannerismProfile"
      }
    },
    "secondary_motion": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/secondaryMotion"
      }
    },
    "style_transforms": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/styleTransform"
      }
    },
    "constraints": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/constraint"
      }
    },
    "verification_plan": {
      "$ref": "#/$defs/verificationPlan"
    },
    "capability_report": {
      "type": "object",
      "additionalProperties": true
    },
    "provenance": {
      "type": "object",
      "additionalProperties": true
    },
    "extensions": {
      "type": "object",
      "propertyNames": {
        "format": "uri"
      },
      "additionalProperties": true
    }
  },
  "additionalProperties": false
}

{
  "type": "string",
  "minLength": 1,
  "maxLength": 256,
  "pattern": "^[A-Za-z0-9_:.\\-/]+$"
}

{
  "type": "number",
  "minimum": 0
}

{
  "type": "array",
  "prefixItems": [
    {
      "type": "number"
    },
    {
      "type": "number"
    },
    {
      "type": "number"
    }
  ],
  "items": false,
  "minItems": 3,
  "maxItems": 3
}

{
  "oneOf": [
    {
      "type": "array",
      "prefixItems": [
        {
          "type": "number"
        },
        {
          "type": "number"
        }
      ],
      "items": false,
      "minItems": 2,
      "maxItems": 2
    },
    {
      "type": "object",
      "required": [
        "start_s",
        "end_s"
      ],
      "properties": {
        "start_s": {
          "type": "number"
        },
        "end_s": {
          "type": "number"
        },
        "boundary_semantics": {
          "enum": [
            "half_open",
            "closed",
            "open",
            "left_open"
          ]
        }
      },
      "additionalProperties": false
    }
  ]
}

{
  "type": "object",
  "required": [
    "numerator",
    "denominator"
  ],
  "properties": {
    "numerator": {
      "type": "integer",
      "minimum": 1
    },
    "denominator": {
      "type": "integer",
      "minimum": 1
    }
  },
  "additionalProperties": false
}

{
  "type": "object",
  "required": [
    "canonical"
  ],
  "properties": {
    "canonical": {
      "enum": [
        "seconds",
        "rational_media_time",
        "simulation_ticks"
      ]
    },
    "fps": {
      "$ref": "#/$defs/fps"
    },
    "sample_rate_hz": {
      "type": "number",
      "exclusiveMinimum": 0
    },
    "source_clock": {
      "type": "string"
    },
    "rounding": {
      "type": "string"
    },
    "interval_semantics": {
      "enum": [
        "half_open",
        "closed",
        "open",
        "left_open"
      ]
    }
  },
  "additionalProperties": false
}

{
  "type": "object",
  "required": [
    "class"
  ],
  "properties": {
    "class": {
      "enum": [
        "measured",
        "detected",
        "inferred",
        "interpreted",
        "authored",
        "defaulted",
        "derived"
      ]
    },
    "source_refs": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/stableId"
      }
    },
    "confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1
    },
    "extractor": {
      "type": "object",
      "properties": {
        "name": {
          "type": "string"
        },
        "version": {
          "type": "string"
        }
      },
      "additionalProperties": true
    },
    "review_status": {
      "enum": [
        "unreviewed",
        "reviewed",
        "locked",
        "rejected"
      ]
    }
  },
  "additionalProperties": false
}

{
  "type": "object",
  "required": [
    "coordinate_system_id",
    "space",
    "handedness",
    "up_axis",
    "linear_unit",
    "angular_unit"
  ],
  "properties": {
    "coordinate_system_id": {
      "$ref": "#/$defs/stableId"
    },
    "space": {
      "type": "string"
    },
    "handedness": {
      "enum": [
        "left",
        "right"
      ]
    },
    "up_axis": {
      "type": "string"
    },
    "forward_axis": {
      "type": "string"
    },
    "origin": {
      "type": [
        "string",
        "array",
        "object"
      ]
    },
    "linear_unit": {
      "type": "string"
    },
    "angular_unit": {
      "type": "string"
    },
    "parent_ref": {
      "$ref": "#/$defs/stableId"
    },
    "transform_to_parent": {
      "type": "array",
      "items": {
        "type": "number"
      },
      "minItems": 16,
      "maxItems": 16
    }
  },
  "additionalProperties": false
}

{
  "type": "object",
  "required": [
    "asset_id",
    "uri"
  ],
  "properties": {
    "asset_id": {
      "$ref": "#/$defs/stableId"
    },
    "uri": {
      "type": "string"
    },
    "media_type": {
      "type": "string"
    },
    "encoding": {
      "type": "string"
    },
    "dtype": {
      "type": "string"
    },
    "shape": {
      "type": "array",
      "items": {
        "type": "integer",
        "minimum": 0
      }
    },
    "semantic": {
      "type": "string"
    },
    "joint_order_ref": {
      "$ref": "#/$defs/stableId"
    },
    "sample_rate_hz": {
      "type": "number",
      "exclusiveMinimum": 0
    },
    "interval": {
      "$ref": "#/$defs/timeInterval"
    },
    "sha256": {
      "type": "string",
      "pattern": "^(REPLACE_WITH_ACTUAL_HASH|[A-Fa-f0-9]{64})$"
    },
    "derived_from": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/stableId"
      }
    },
    "metadata": {
      "type": "object",
      "additionalProperties": true
    }
  },
  "additionalProperties": false
}

{
  "type": "object",
  "required": [
    "entity_id",
    "type"
  ],
  "properties": {
    "entity_id": {
      "$ref": "#/$defs/stableId"
    },
    "type": {
      "type": "string"
    },
    "label": {
      "type": "string"
    },
    "metadata": {
      "type": "object",
      "additionalProperties": true
    }
  },
  "additionalProperties": false
}

{
  "type": "object",
