    },
    "mannerism_profile_ref": {
      "$ref": "#/$defs/stableId"
    },
    "morphology_profile": {
      "type": "object",
      "additionalProperties": true
    },
    "metadata": {
      "type": "object",
      "additionalProperties": true
    }
  },
  "additionalProperties": false
}

{
