    },
    "joint_limit_profile_ref": {
      "$ref": "#/$defs/stableId"
    },
    "retarget_map_ref": {
      "$ref": "#/$defs/stableId"
    },
    "metadata": {
      "type": "object",
      "additionalProperties": true
