      "items": {
        "type": "object",
        "additionalProperties": true
      }
    },
    "metadata": {
      "type": "object",
      "additionalProperties": true
    }
  },
  "additionalProperties": false
}

{
  "type": "object",
  "required": [
    "shot_id",
    "interval"
  ],
  "properties": {
    "shot_id": {
      "$ref": "#/$defs/stableId"
    },
    "interval": {
      "$ref": "#/$defs/timeInterval"
    },
    "camera": {
      "$ref": "#/$defs/camera"
    },
    "beats": {
      "type": "array",
